<?php
/** Expense form with trip/vehicle/category attribution. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/expense_functions.php';requireAuth();enforceModuleAccess('expenses');if($_SERVER['REQUEST_METHOD']==='POST'){if(!verifyCsrfToken((string)($_POST['csrf_token']??''))){setFlash('danger','Invalid form token.');redirect('modules/expenses/add.php');}[$ok,$r]=saveExpense($_POST);setFlash($ok?'success':'danger',$ok?'Expense recorded.':implode(' ',(array)$r));redirect($ok?'modules/expenses/view.php?id='.$r:'modules/expenses/add.php');}$vehicles=getDb()->query('SELECT id,registration_number FROM vehicles WHERE deleted_at IS NULL ORDER BY registration_number')->fetchAll();$trips=getDb()->query('SELECT id,trip_number FROM trips WHERE status="Dispatched" ORDER BY id DESC')->fetchAll();$categories=getDb()->query('SELECT id,name FROM expense_categories WHERE status="Active" ORDER BY name')->fetchAll();$pageTitle='Add expense';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content expense-module"><?php require ROOT_PATH.'/includes/navbar.php';?><h1 class="page-title">Record expense</h1><p class="page-subtitle">Assign costs to the appropriate vehicle, active trip, and category.</p><form class="card dashboard-card expense-form" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><div class="form-grid"><div class="form-group"><label>Expense title</label><input name="title" required></div><div class="form-group"><label>Amount</label><input name="amount" type="number" min=".01" step=".01" required></div><div class="form-group"><label>Vehicle</label><select name="vehicle_id"><option value="">Not vehicle-specific</option><?php foreach($vehicles as $v):?><option value="<?=$v['id']?>"><?=e($v['registration_number'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Active trip</label><select name="trip_id"><option value="">No trip</option><?php foreach($trips as $t):?><option value="<?=$t['id']?>"><?=e($t['trip_number'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Category</label><select name="expense_category_id"><?php foreach($categories as $c):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Expense type</label><input name="expense_type" value="Miscellaneous"></div><div class="form-group"><label>Vendor</label><input name="vendor_name"></div><div class="form-group"><label>Invoice number</label><input name="invoice_number"></div><div class="form-group"><label>Expense date</label><input name="expense_date" type="date" max="<?=date('Y-m-d')?>" required></div></div><div class="form-group"><label>Description</label><textarea name="description"></textarea></div><div class="form-group"><label>Remarks</label><textarea name="remarks"></textarea></div><div class="form-actions"><button class="btn btn-primary">Save expense</button><a class="btn btn-secondary" href="index.php">Cancel</a></div></form></main><?php require ROOT_PATH.'/includes/footer.php';?>
